async function run() {
  const target = await getTargetChannel();
  const now = new Date();
  const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

  const result = await summarizeChannel({
    channelId: target.channelId,
    fromIso: yesterday.toISOString(),
    toIso: now.toISOString(),
  });

  return result;
}

run().then(result => {
    // The tool expects the return value to be the object itself
    // The sandbox environment handles the return value.
    console.log(JSON.stringify(result));
});

async function run() {
  const target = await getTargetChannel();
  console.log("Target channel:", target);

  const now = new Date();
  const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

  const params = {
    channelId: target.channelId,
    fromIso: yesterday.toISOString(),
    toIso: now.toISOString()
  };
  console.log("Params:", params);

  return await summarizeChannel(params);
}

run().then(console.log).catch(console.error);

